/*
 * src/views/glossaryDrawer.ts — Glossary drawer wiring.
 * Lazy-loads the glossary engine on first open, debounces search,
 * filters by category, and renders expandable term cards.
 */
import { loadGlossary } from '../glossary/glossaryEngine.js';
import type {
  GlossaryEngine,
  GlossaryTerm,
  GlossaryCategory,
} from '../glossary/glossaryEngine.js';

interface DrawerState {
  engine: GlossaryEngine | null;
  query: string;
  category: GlossaryCategory | 'all';
  expandedId: string | null;
}

const state: DrawerState = {
  engine: null,
  query: '',
  category: 'all',
  expandedId: null,
};

const RISK_LABEL: Record<string, string> = {
  low: 'low risk',
  medium: 'medium risk',
  high: 'high risk',
  critical: 'critical risk',
};

const CATEGORY_LABEL: Record<string, string> = {
  all: 'All',
  incoterm: 'Incoterms',
  trade_instrument: 'Trade Finance',
  regulation: 'Regulatory',
  logistics: 'Logistics',
  commodity_class: 'Commodity',
  chokepoint: 'Chokepoints',
  market_structure: 'Market Structure',
};

function escapeHtml(s: string): string {
  return s
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function renderCategoryChips(): void {
  const wrap = document.getElementById('glossaryCategoryChips');
  if (!wrap || !state.engine) return;
  const cats: Array<GlossaryCategory | 'all'> = [
    'all',
    'incoterm',
    'trade_instrument',
    'regulation',
    'logistics',
    'chokepoint',
    'market_structure',
  ];
  wrap.innerHTML = cats
    .map((c) => {
      const active = c === state.category ? ' active' : '';
      const label = CATEGORY_LABEL[c] ?? c;
      return `<button type="button" class="chip${active}" data-glossary-cat="${c}">${escapeHtml(label)}</button>`;
    })
    .join('');
  wrap.querySelectorAll<HTMLButtonElement>('[data-glossary-cat]').forEach((btn) => {
    btn.addEventListener('click', () => {
      state.category = btn.dataset.glossaryCat as GlossaryCategory | 'all';
      renderCategoryChips();
      renderResults();
    });
  });
}

function termCardHtml(t: GlossaryTerm, expanded: boolean): string {
  const riskCls = `gl-risk gl-risk-${t.riskClass}`;
  const catLabel = CATEGORY_LABEL[t.category] ?? t.category;
  const reg = t.regulatoryBody ? `<span class="gl-reg">${escapeHtml(t.regulatoryBody)}</span>` : '';
  let detail = '';
  if (expanded) {
    const stages = (t.applicableStages ?? []).map((s) => `<span class="gl-stage">${escapeHtml(s)}</span>`).join('');
    const related = (state.engine?.getRelated(t.id) ?? [])
      .slice(0, 12)
      .map((r) => `<button type="button" class="gl-related" data-glossary-jump="${r.id}">${escapeHtml(r.term)}</button>`)
      .join('');
    let boundary = '';
    if (t.incotermsRiskBoundary) {
      boundary = `
        <div class="gl-boundary">
          <div><b>Seller risk through:</b> ${escapeHtml(t.incotermsRiskBoundary.sellerOwnsRiskThrough)}</div>
          <div><b>Buyer risk from:</b> ${escapeHtml(t.incotermsRiskBoundary.buyerOwnsRiskFrom)}</div>
        </div>`;
    }
    detail = `
      <div class="gl-detail">
        <p>${escapeHtml(t.definition)}</p>
        ${boundary}
        ${stages ? `<div class="gl-stages">${stages}</div>` : ''}
        ${related ? `<div class="gl-related-row"><span class="gl-related-label">Related</span>${related}</div>` : ''}
      </div>`;
  }
  return `
    <article class="gl-card${expanded ? ' gl-open' : ''}" data-glossary-id="${t.id}">
      <header class="gl-head">
        <div class="gl-title-wrap">
          <h4 class="gl-term">${escapeHtml(t.term)}</h4>
          <p class="gl-short">${escapeHtml(t.shortDef)}</p>
        </div>
        <div class="gl-meta">
          <span class="gl-cat">${escapeHtml(catLabel)}</span>
          <span class="${riskCls}">${escapeHtml(RISK_LABEL[t.riskClass] ?? t.riskClass)}</span>
          ${reg}
        </div>
      </header>
      ${detail}
    </article>`;
}

function renderResults(): void {
  const out = document.getElementById('glossaryResults');
  if (!out || !state.engine) return;
  let terms: GlossaryTerm[];
  if (state.query.trim()) {
    terms = state.engine.search(state.query, 60);
    if (state.category !== 'all') {
      terms = terms.filter((t) => t.category === state.category);
    }
  } else if (state.category !== 'all') {
    terms = state.engine.getByCategory(state.category as GlossaryCategory)
      .slice()
      .sort((a, b) => a.term.localeCompare(b.term));
  } else {
    terms = state.engine.all().slice().sort((a, b) => a.term.localeCompare(b.term));
  }

  if (!terms.length) {
    out.innerHTML = '<div class="gl-empty">No terms match. Try fewer words or change category.</div>';
    return;
  }

  out.innerHTML = terms.map((t) => termCardHtml(t, t.id === state.expandedId)).join('');
  out.querySelectorAll<HTMLElement>('.gl-card').forEach((el) => {
    const id = el.dataset.glossaryId;
    if (!id) return;
    el.querySelector('.gl-head')?.addEventListener('click', () => {
      state.expandedId = state.expandedId === id ? null : id;
      renderResults();
    });
  });
  out.querySelectorAll<HTMLButtonElement>('[data-glossary-jump]').forEach((btn) => {
    btn.addEventListener('click', (e) => {
      e.stopPropagation();
      const target = btn.dataset.glossaryJump;
      if (!target) return;
      state.expandedId = target;
      // Clear the query so the jump target is visible.
      state.query = '';
      const input = document.getElementById('glossarySearch') as HTMLInputElement | null;
      if (input) input.value = '';
      renderResults();
      const card = document.querySelector(`[data-glossary-id="${target}"]`);
      card?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    });
  });
}

let debounceHandle: number | null = null;

function bindSearchInput(): void {
  const input = document.getElementById('glossarySearch') as HTMLInputElement | null;
  if (!input) return;
  input.addEventListener('input', () => {
    if (debounceHandle !== null) window.clearTimeout(debounceHandle);
    debounceHandle = window.setTimeout(() => {
      state.query = input.value;
      renderResults();
    }, 150);
  });
}

async function ensureEngine(): Promise<void> {
  if (state.engine) return;
  state.engine = await loadGlossary();
  const countEl = document.getElementById('glossaryCount');
  if (countEl) countEl.textContent = `${state.engine.all().length} terms`;
  renderCategoryChips();
  renderResults();
}

async function openGlossaryTerm(termId: string): Promise<void> {
  await ensureEngine();
  const term = state.engine?.getById(termId);
  if (!term) return;
  state.query = '';
  state.category = 'all';
  state.expandedId = termId;
  const input = document.getElementById('glossarySearch') as HTMLInputElement | null;
  if (input) input.value = '';
  renderCategoryChips();
  renderResults();
  window.setTimeout(() => {
    document.querySelector(`[data-glossary-id="${termId}"]`)?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }, 40);
}

let initialized = false;

export function initGlossaryDrawer(): void {
  if (initialized) return;
  initialized = true;
  bindSearchInput();

  // Lazy-load on first drawer open, both for the topbar button and for any
  // future programmatic opener.
  const btn = document.getElementById('btnGlossary');
  btn?.addEventListener('click', () => {
    void ensureEngine();
  });

  window.addEventListener('heimdall:open-glossary-term', (event) => {
    const termId = (event as CustomEvent<{ termId?: string }>).detail?.termId;
    if (!termId) return;
    const opener = (window as any).__heimdallOpenDrawer as ((id: string) => void) | undefined;
    if (typeof opener === 'function') opener('drawerGlossary');
    else btn?.dispatchEvent(new MouseEvent('click', { bubbles: true }));
    void openGlossaryTerm(termId);
  });

  // Also catch the case where the drawer is opened via class manipulation
  // (the legacy app exposes openDrawer / closeDrawer helpers via data-attrs).
  const drawer = document.getElementById('drawerGlossary');
  if (drawer) {
    const obs = new MutationObserver(() => {
      if (drawer.classList.contains('open') || drawer.classList.contains('hd-open')) {
        void ensureEngine();
      }
    });
    obs.observe(drawer, { attributes: true, attributeFilter: ['class'] });
  }
}
