/*
 * src/services/monteCarloUpgrade.ts — Phase-3 Monte Carlo upgrade.
 *
 * Hijacks the legacy `mcRunBtn` click in src/app.ts and runs an
 * upgraded simulation against the same live route + state inputs
 * (exposed via window.__heimdallApi by app.ts). Renders:
 *   - violin plot (KDE) of lead-time samples
 *   - VaR card (delta over baseline at P95)
 *   - bottleneck-distribution donut wheel
 *   - keeps the legacy P50/P80/P95 horizontal bands intact below
 *
 * Sampling per iteration per leg:
 *   - LogNormal duration centred on baseDays (mean), sd derived from
 *     the legacy [days_lo, days_hi] range
 *   - Macro shocks scale the mean (deterministic)
 *   - Bernoulli inspection × failure adds dwell delay
 *   - Beta(2,2) shock severity scaled by leg base severity
 *   - Correlated chokepoint shocks via shared Exponential factors
 */
import correlationDataset from '../../data/chokepoint-correlations.v1.json' with { type: 'json' };

interface AppApi {
  getRoute: () => any;
  getState: () => any;
  inferLegMode: (from: any, to: any) => string;
  averageDays: (node: any) => number;
  severityForLeg: (mode: string) => number;
  getChain?: () => any;
}

interface LegSnapshot {
  index: number;
  legId: string;
  fromName: string;
  toName: string;
  mode: string;
  baseDays: number;
  sd: number;
  baseSeverity: number;
  corridorIds: string[]; // chokepoint ids that this leg is exposed to
}

interface IterationResult {
  totalDays: number;
  totalCost: number;
  legContribDays: number[];
}

interface McResult {
  iterations: number;
  legs: LegSnapshot[];
  days: { p50: number; p80: number; p95: number; min: number; max: number; samples: number[] };
  cost: { p50: number; p80: number; p95: number };
  baselineDays: number;
  baselineCost: number;
  varDaysAtP95: number;
  varCostAtP95: number;
  bottleneckDistribution: Array<{ legId: string; legName: string; pct: number }>;
}

// ── Probability helpers ──────────────────────────────────────────────
function randNorm(): number {
  // Box-Muller
  let u = 0;
  let v = 0;
  while (u === 0) u = Math.random();
  while (v === 0) v = Math.random();
  return Math.sqrt(-2 * Math.log(u)) * Math.cos(2 * Math.PI * v);
}

function lognormal(mean: number, sd: number): number {
  if (mean <= 0) return 0;
  const variance = sd * sd;
  const m2 = mean * mean;
  const sigma = Math.sqrt(Math.log(1 + variance / m2));
  const mu = Math.log(m2 / Math.sqrt(m2 + variance));
  return Math.exp(mu + sigma * randNorm());
}

function beta22(): number {
  // Beta(2,2) sample via order-statistics: median of three uniforms.
  const a = Math.random();
  const b = Math.random();
  const c = Math.random();
  return [a, b, c].sort()[1];
}

function exponential(scaleHours: number): number {
  if (scaleHours <= 0) return 0;
  return -Math.log(1 - Math.random()) * scaleHours;
}

function quantile(sortedAsc: number[], p: number): number {
  if (!sortedAsc.length) return 0;
  const i = Math.min(sortedAsc.length - 1, Math.max(0, Math.floor(sortedAsc.length * p)));
  return sortedAsc[i];
}

// ── Corridor detection ────────────────────────────────────────────────
const CHOKEPOINT_IDS = [
  'suez',
  'hormuz',
  'malacca',
  'panama',
  'cape-horn',
  'cape-good-hope',
  'bosphorus',
  'taiwan-strait',
];

const CHOKEPOINT_BBOX: Record<string, { latLo: number; latHi: number; lngLo: number; lngHi: number }> = {
  suez:             { latLo: 27,  latHi: 33,  lngLo: 31,  lngHi: 33  },
  hormuz:           { latLo: 24,  latHi: 28,  lngLo: 54,  lngHi: 58  },
  malacca:          { latLo: -1,  latHi: 6,   lngLo: 99,  lngHi: 105 },
  panama:           { latLo: 7,   latHi: 11,  lngLo: -82, lngHi: -78 },
  'cape-horn':      { latLo: -57, latHi: -53, lngLo: -71, lngHi: -65 },
  'cape-good-hope': { latLo: -36, latHi: -32, lngLo: 17,  lngHi: 21  },
  bosphorus:        { latLo: 40,  latHi: 42,  lngLo: 28,  lngHi: 30  },
  'taiwan-strait':  { latLo: 22,  latHi: 27,  lngLo: 117, lngHi: 122 },
};

function legCrossesChokepoint(from: any, to: any, mode: string): string[] {
  // Heuristic: only sea legs cross chokepoints. Mark a chokepoint as exposed
  // if the great-circle bounding box between the leg endpoints contains the
  // chokepoint's latitude band.
  if (mode !== 'sea') return [];
  const fromLat = from.coords[0];
  const toLat = to.coords[0];
  const fromLng = from.coords[1];
  const toLng = to.coords[1];
  const minLat = Math.min(fromLat, toLat) - 8;
  const maxLat = Math.max(fromLat, toLat) + 8;
  const minLng = Math.min(fromLng, toLng) - 12;
  const maxLng = Math.max(fromLng, toLng) + 12;
  const out: string[] = [];
  for (const id of CHOKEPOINT_IDS) {
    const b = CHOKEPOINT_BBOX[id];
    if (b.latHi < minLat || b.latLo > maxLat) continue;
    if (b.lngHi < minLng || b.lngLo > maxLng) continue;
    out.push(id);
  }
  return out;
}

// ── Build leg snapshots from the live route ───────────────────────────
function snapshotLegs(api: AppApi): LegSnapshot[] {
  const route = api.getRoute();
  const legs: LegSnapshot[] = [];
  if (!route?.nodes?.length) return legs;
  for (let i = 1; i < route.nodes.length; i++) {
    const from = route.nodes[i - 1];
    const to = route.nodes[i];
    const mode = api.inferLegMode(from, to);
    const baseDays = api.averageDays(to);
    // Rough sd from legacy [days_lo, days_hi] window (1σ ≈ range / 4).
    const range = Array.isArray(to.days) && to.days.length === 2 ? to.days[1] - to.days[0] : baseDays * 0.4;
    const sd = Math.max(0.25, range / 4);
    const baseSeverity = api.severityForLeg(mode);
    legs.push({
      index: i,
      legId: `${from.id ?? from.name ?? `n${i - 1}`}->${to.id ?? to.name ?? `n${i}`}`,
      fromName: from.name ?? `Node ${i - 1}`,
      toName: to.name ?? `Node ${i}`,
      mode,
      baseDays,
      sd,
      baseSeverity,
      corridorIds: legCrossesChokepoint(from, to, mode),
    });
  }
  return legs;
}

function buildCorrelationFactor(): { sample: () => Map<string, number> } {
  // Crude correlated-shock model: each iteration, draw an Exponential
  // shock per chokepoint scaled to its `scaleHoursByCorridor`. Apply the
  // declared pairwise correlations by blending shocks: shock_b += rho * shock_a.
  const data = correlationDataset as any;
  const scales: Record<string, number> = (data?.shockDistribution?.scaleHoursByCorridor) ?? {};
  const correlations: Array<{ corridorA: string; corridorB: string; rho: number }> = data?.correlations ?? [];
  return {
    sample(): Map<string, number> {
      const draws = new Map<string, number>();
      for (const id of CHOKEPOINT_IDS) {
        const scale = scales[id] ?? 18;
        // Most iterations should see no shock — shock probability ~ 1 / (1 + scale/8)
        const shockProb = Math.min(0.45, 8 / (8 + scale));
        const occur = Math.random() < shockProb;
        draws.set(id, occur ? exponential(scale) : 0);
      }
      // Apply correlations as additive cross-terms.
      const blended = new Map(draws);
      for (const c of correlations) {
        const a = draws.get(c.corridorA) ?? 0;
        if (a === 0) continue;
        const cur = blended.get(c.corridorB) ?? 0;
        blended.set(c.corridorB, cur + c.rho * a);
      }
      return blended;
    },
  };
}

// ── Core simulation ───────────────────────────────────────────────────
function runUpgradedSim(api: AppApi, iterations: number): McResult {
  const legs = snapshotLegs(api);
  const state = api.getState() ?? {};
  const shocks = state.shocks ?? { congestion: 0, fuel: 0, demand: 0, policy: 0 };
  const corr = buildCorrelationFactor();

  const dailySamples: number[] = new Array(iterations);
  const costSamples: number[] = new Array(iterations);
  const legContribAccum = legs.map(() => 0);
  const legBottleneckCounts = legs.map(() => 0);

  let baselineDaysSum = 0;
  let baselineCostSum = 0;

  for (let r = 0; r < iterations; r++) {
    let totalDays = 0;
    let totalCost = 0;
    const contribDays = new Array(legs.length).fill(0);
    const corridorShocks = corr.sample();

    for (let i = 0; i < legs.length; i++) {
      const leg = legs[i];
      // Macro multipliers (deterministic)
      const macroTime = 1
        + shocks.congestion * (leg.mode === 'sea' ? 0.0048 : 0.0038)
        + shocks.demand * 0.0017
        + shocks.policy * 0.0024;
      const macroCost = 1
        + shocks.fuel * (leg.mode === 'air' ? 0.0060 : leg.mode === 'sea' ? 0.0046 : 0.0031)
        + shocks.congestion * 0.0018;

      // LogNormal duration sample (in days)
      const sampledDays = lognormal(Math.max(0.25, leg.baseDays * macroTime), leg.sd);

      // Beta(2,2) severity multiplier centred on legacy base severity
      const severityMult = 0.35 + beta22() * 1.30; // ~[0.35..1.65]
      const sevDelay = leg.baseSeverity * severityMult * (leg.mode === 'sea' ? 0.34 : leg.mode === 'air' ? 0.10 : 0.06) * leg.baseDays;

      // Corridor-shock additional dwell (hours -> days)
      let corridorDelayDays = 0;
      for (const cid of leg.corridorIds) {
        corridorDelayDays += (corridorShocks.get(cid) ?? 0) / 24;
      }

      // Bernoulli inspection × failure (1.5% chance per leg, adds 30% of base dwell)
      const inspectionFail = Math.random() < 0.015 ? leg.baseDays * 0.30 : 0;

      const legDays = sampledDays + sevDelay + corridorDelayDays + inspectionFail;
      contribDays[i] = legDays;
      totalDays += legDays;

      // Cost: base 100 USD-units per leg scaled by macro + severity + a small Gaussian noise
      const legCost = 100 * macroCost * (1 + leg.baseSeverity * severityMult * 0.32) * (0.9 + 0.2 * Math.random());
      totalCost += legCost;

      baselineDaysSum += leg.baseDays;
      baselineCostSum += 100 * (1 + leg.baseSeverity * 0.5);
    }

    dailySamples[r] = totalDays;
    costSamples[r] = totalCost;

    for (let i = 0; i < legs.length; i++) legContribAccum[i] += contribDays[i];
    // Identify dominant leg this iteration
    let maxIdx = 0;
    let maxVal = -Infinity;
    for (let i = 0; i < legs.length; i++) {
      if (contribDays[i] > maxVal) {
        maxVal = contribDays[i];
        maxIdx = i;
      }
    }
    legBottleneckCounts[maxIdx]++;
  }

  const sortedDays = dailySamples.slice().sort((a, b) => a - b);
  const sortedCost = costSamples.slice().sort((a, b) => a - b);
  const baselineDays = iterations ? baselineDaysSum / iterations : 0;
  const baselineCost = iterations ? baselineCostSum / iterations : 0;

  const bottleneck = legs
    .map((leg, i) => ({
      legId: leg.legId,
      legName: `${leg.fromName} → ${leg.toName}`,
      pct: iterations ? (legBottleneckCounts[i] / iterations) * 100 : 0,
    }))
    .sort((a, b) => b.pct - a.pct);

  return {
    iterations,
    legs,
    days: {
      p50: quantile(sortedDays, 0.5),
      p80: quantile(sortedDays, 0.8),
      p95: quantile(sortedDays, 0.95),
      min: sortedDays[0] ?? 0,
      max: sortedDays[sortedDays.length - 1] ?? 0,
      samples: sortedDays,
    },
    cost: {
      p50: quantile(sortedCost, 0.5),
      p80: quantile(sortedCost, 0.8),
      p95: quantile(sortedCost, 0.95),
    },
    baselineDays,
    baselineCost,
    varDaysAtP95: quantile(sortedDays, 0.95) - baselineDays,
    varCostAtP95: quantile(sortedCost, 0.95) - baselineCost,
    bottleneckDistribution: bottleneck,
  };
}

// ── SVG rendering ────────────────────────────────────────────────────
function escapeHtml(s: string): string {
  return s.replace(/[&<>"']/g, (ch) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[ch] as string));
}

function silvermanBandwidth(samples: number[]): number {
  const n = samples.length;
  if (n < 2) return 1;
  const mean = samples.reduce((a, b) => a + b, 0) / n;
  const variance = samples.reduce((s, x) => s + (x - mean) ** 2, 0) / (n - 1);
  const sd = Math.sqrt(variance);
  // Use IQR-based robust scale too
  const sorted = samples.slice().sort((a, b) => a - b);
  const q1 = quantile(sorted, 0.25);
  const q3 = quantile(sorted, 0.75);
  const iqr = q3 - q1;
  const a = Math.min(sd, iqr / 1.34) || sd || 1;
  return 0.9 * a * Math.pow(n, -1 / 5);
}

function gaussianKDE(samples: number[], xs: number[], h: number): number[] {
  const n = samples.length;
  if (!n) return xs.map(() => 0);
  const norm = 1 / (n * h * Math.sqrt(2 * Math.PI));
  return xs.map((x) => {
    let sum = 0;
    for (let i = 0; i < n; i++) {
      const u = (x - samples[i]) / h;
      sum += Math.exp(-0.5 * u * u);
    }
    return sum * norm;
  });
}

function renderViolin(container: HTMLElement, samples: number[], baseline: number, p50: number, p95: number): void {
  const minX = Math.min(...samples);
  const maxX = Math.max(...samples);
  const padX = (maxX - minX) * 0.06 || 1;
  const xLo = minX - padX;
  const xHi = maxX + padX;
  const W = 600;
  const H = 140;
  const padL = 20;
  const padR = 20;
  const padT = 12;
  const padB = 26;
  const innerW = W - padL - padR;
  const innerH = H - padT - padB;
  const N = 80;
  const xs: number[] = new Array(N).fill(0).map((_, i) => xLo + (xHi - xLo) * (i / (N - 1)));
  const h = silvermanBandwidth(samples);
  const ys = gaussianKDE(samples, xs, h);
  const maxY = Math.max(...ys);
  const sx = (x: number) => padL + ((x - xLo) / (xHi - xLo)) * innerW;
  const sy = (y: number) => (y / (maxY || 1)) * (innerH / 2);
  // Build symmetric polygon
  const top: string[] = [];
  const bot: string[] = [];
  for (let i = 0; i < N; i++) {
    const x = sx(xs[i]);
    const y = sy(ys[i]);
    top.push(`${x.toFixed(2)},${(padT + innerH / 2 - y).toFixed(2)}`);
    bot.push(`${x.toFixed(2)},${(padT + innerH / 2 + y).toFixed(2)}`);
  }
  const polygon = top.join(' ') + ' ' + bot.reverse().join(' ');
  const baseX = sx(Math.max(xLo, Math.min(xHi, baseline)));
  const p50X = sx(p50);
  const p95X = sx(p95);
  const axisY = padT + innerH / 2 + innerH / 2 + 4;
  const ticks = 5;
  const tickEls: string[] = [];
  for (let t = 0; t <= ticks; t++) {
    const v = xLo + (xHi - xLo) * (t / ticks);
    const x = sx(v);
    tickEls.push(
      `<line x1="${x.toFixed(1)}" y1="${(padT + innerH).toFixed(1)}" x2="${x.toFixed(1)}" y2="${(padT + innerH + 3).toFixed(1)}" stroke="rgba(31,42,58,0.35)" stroke-width="1"/>` +
      `<text x="${x.toFixed(1)}" y="${(axisY + 8).toFixed(1)}" text-anchor="middle" font-family="JetBrains Mono, monospace" font-size="9" fill="rgba(31,42,58,0.65)">${v.toFixed(0)}d</text>`,
    );
  }
  container.innerHTML = `
    <svg class="mc-violin-svg" viewBox="0 0 ${W} ${H}" preserveAspectRatio="none" aria-label="Lead-time distribution violin plot">
      <polygon points="${polygon}" fill="rgba(35,116,171,0.18)" stroke="#2374ab" stroke-width="1"/>
      <line x1="${baseX.toFixed(1)}" y1="${padT}" x2="${baseX.toFixed(1)}" y2="${(padT + innerH).toFixed(1)}" stroke="#3f8e6e" stroke-width="1.5" stroke-dasharray="3,3"/>
      <line x1="${p50X.toFixed(1)}" y1="${padT}" x2="${p50X.toFixed(1)}" y2="${(padT + innerH).toFixed(1)}" stroke="#1f2a3a" stroke-width="1.5"/>
      <line x1="${p95X.toFixed(1)}" y1="${padT}" x2="${p95X.toFixed(1)}" y2="${(padT + innerH).toFixed(1)}" stroke="#c94b4b" stroke-width="1.5"/>
      <text x="${baseX.toFixed(1)}" y="${(padT - 2).toFixed(1)}" text-anchor="middle" font-family="JetBrains Mono, monospace" font-size="9" fill="#3f8e6e">base</text>
      <text x="${p50X.toFixed(1)}" y="${(padT - 2).toFixed(1)}" text-anchor="middle" font-family="JetBrains Mono, monospace" font-size="9" fill="#1f2a3a">P50</text>
      <text x="${p95X.toFixed(1)}" y="${(padT - 2).toFixed(1)}" text-anchor="middle" font-family="JetBrains Mono, monospace" font-size="9" fill="#c94b4b">P95</text>
      <line x1="${padL}" y1="${(padT + innerH).toFixed(1)}" x2="${(W - padR).toFixed(1)}" y2="${(padT + innerH).toFixed(1)}" stroke="rgba(31,42,58,0.35)" stroke-width="1"/>
      ${tickEls.join('')}
    </svg>`;
}

function renderVarCard(container: HTMLElement, mc: McResult): void {
  const dDays = Math.max(0, mc.varDaysAtP95);
  const dCost = Math.max(0, mc.varCostAtP95);
  container.innerHTML = `
    <div class="mc-var-card" role="group" aria-label="Value at Risk at P95">
      <div class="mc-var-block">
        <div class="mc-var-label">VaR @ P95 — Time</div>
        <div class="mc-var-value">+${dDays.toFixed(1)} d</div>
        <div class="mc-var-sub">vs baseline ${mc.baselineDays.toFixed(1)} d</div>
      </div>
      <div class="mc-var-block">
        <div class="mc-var-label">VaR @ P95 — Cost</div>
        <div class="mc-var-value">+${dCost.toFixed(0)} units</div>
        <div class="mc-var-sub">vs baseline ${mc.baselineCost.toFixed(0)} units</div>
      </div>
    </div>`;
}

function renderBottleneckWheel(container: HTMLElement, mc: McResult): void {
  const top = mc.bottleneckDistribution.filter((b) => b.pct >= 0.5).slice(0, 6);
  if (!top.length) {
    container.innerHTML = '';
    return;
  }
  const colors = ['#2374ab', '#c94b4b', '#f59e0b', '#3f8e6e', '#7a8ba0', '#9b59b6'];
  const total = top.reduce((s, b) => s + b.pct, 0) || 1;
  const cx = 48;
  const cy = 48;
  const rOuter = 44;
  const rInner = 26;
  let acc = 0;
  const arcs: string[] = [];
  top.forEach((b, i) => {
    const startAngle = (acc / total) * 2 * Math.PI - Math.PI / 2;
    acc += b.pct;
    const endAngle = (acc / total) * 2 * Math.PI - Math.PI / 2;
    const large = endAngle - startAngle > Math.PI ? 1 : 0;
    const x1 = cx + rOuter * Math.cos(startAngle);
    const y1 = cy + rOuter * Math.sin(startAngle);
    const x2 = cx + rOuter * Math.cos(endAngle);
    const y2 = cy + rOuter * Math.sin(endAngle);
    const x3 = cx + rInner * Math.cos(endAngle);
    const y3 = cy + rInner * Math.sin(endAngle);
    const x4 = cx + rInner * Math.cos(startAngle);
    const y4 = cy + rInner * Math.sin(startAngle);
    const path = `M ${x1.toFixed(2)} ${y1.toFixed(2)} A ${rOuter} ${rOuter} 0 ${large} 1 ${x2.toFixed(2)} ${y2.toFixed(2)} L ${x3.toFixed(2)} ${y3.toFixed(2)} A ${rInner} ${rInner} 0 ${large} 0 ${x4.toFixed(2)} ${y4.toFixed(2)} Z`;
    arcs.push(`<path d="${path}" fill="${colors[i % colors.length]}" stroke="#fff" stroke-width="0.5" />`);
  });
  const legend = top.map((b, i) => {
    const color = colors[i % colors.length];
    return `<div class="mc-bw-row"><span class="mc-bw-dot" style="background:${color}"></span><span class="mc-bw-name">${escapeHtml(b.legName)}</span><span class="mc-bw-pct">${b.pct.toFixed(0)}%</span></div>`;
  }).join('');
  container.innerHTML = `
    <div class="mc-bottleneck-wheel" role="group" aria-label="Bottleneck distribution">
      <svg class="mc-bw-svg" viewBox="0 0 96 96" aria-hidden="true">${arcs.join('')}</svg>
      <div class="mc-bw-legend">
        <div style="font-size:10px;text-transform:uppercase;letter-spacing:0.06em;color:var(--muted);font-weight:700;margin-bottom:3px">Top bottlenecks</div>
        ${legend}
      </div>
    </div>`;
}

function ensureContainers(parent: HTMLElement): {
  violin: HTMLElement;
  varCard: HTMLElement;
  wheel: HTMLElement;
} {
  let violin = document.getElementById('mcUpgradeViolin') as HTMLElement | null;
  let varCard = document.getElementById('mcUpgradeVar') as HTMLElement | null;
  let wheel = document.getElementById('mcUpgradeWheel') as HTMLElement | null;
  if (!violin) {
    violin = document.createElement('div');
    violin.id = 'mcUpgradeViolin';
    violin.className = 'mc-violin-wrap';
    parent.appendChild(violin);
  }
  if (!varCard) {
    varCard = document.createElement('div');
    varCard.id = 'mcUpgradeVar';
    parent.appendChild(varCard);
  }
  if (!wheel) {
    wheel = document.createElement('div');
    wheel.id = 'mcUpgradeWheel';
    parent.appendChild(wheel);
  }
  return { violin, varCard, wheel };
}

// ── Wiring ────────────────────────────────────────────────────────────
let bound = false;

function bind(api: AppApi): void {
  if (bound) return;
  const btn = document.getElementById('mcRunBtn') as HTMLButtonElement | null;
  const iterSel = document.getElementById('mcIterCount') as HTMLSelectElement | null;
  const results = document.getElementById('mcResults') as HTMLElement | null;
  if (!btn || !iterSel || !results) return;
  bound = true;

  btn.addEventListener(
    'click',
    () => {
      // Defer to allow legacy click handler to run too — its results render
      // first; we then layer the upgraded analytics on top.
      window.setTimeout(() => {
        try {
          const iterations = Number(iterSel.value) || 500;
          const mc = runUpgradedSim(api, iterations);
          if (!mc.legs.length) return;
          const { violin, varCard, wheel } = ensureContainers(results);
          renderVarCard(varCard, mc);
          renderViolin(violin, mc.days.samples, mc.baselineDays, mc.days.p50, mc.days.p95);
          renderBottleneckWheel(wheel, mc);
        } catch (err) {
          console.error('[heimdall] MC upgrade failed', err);
        }
      }, 60);
    },
    false,
  );
}

let initCalled = false;

export function initMonteCarloUpgrade(): void {
  if (initCalled) return;
  initCalled = true;

  const tryBind = (): void => {
    const api = (window as any).__heimdallApi as AppApi | undefined;
    if (api && typeof api.getRoute === 'function' && typeof api.getState === 'function') bind(api);
  };

  tryBind();
  window.addEventListener('heimdall:ready', tryBind);
  // Fallback poll for first 5s in case the listener was attached late.
  let tries = 0;
  const poll = window.setInterval(() => {
    tries++;
    tryBind();
    if (bound || tries > 25) window.clearInterval(poll);
  }, 200);
}
