export interface ConfidenceComponents {
  geometrySource: number;
  dataFreshness: number;
  geopoliticalStability: number;
  corridorDisruptionHistory: number;
  routeComplexity: number;
}

export interface ConfidenceScore {
  score: number;
  components: ConfidenceComponents;
  explanation: string;
}

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

export function computeConfidence(components: ConfidenceComponents): number {
  const raw = components.geometrySource
    * (1 + components.dataFreshness)
    * components.geopoliticalStability
    * components.corridorDisruptionHistory
    * components.routeComplexity;
  return clamp(raw, 0.05, 0.97);
}

export function scoreLegacyRouteConfidence(route: {
  confidence?: number;
  baseRisk?: number;
  nodes?: unknown[];
  badge?: string;
}): ConfidenceScore {
  const legacyConfidence = typeof route.confidence === 'number' ? route.confidence : 70;
  const baseRisk = typeof route.baseRisk === 'number' ? route.baseRisk : 45;
  const legCount = Math.max(1, (route.nodes?.length ?? 2) - 1);
  const geometrySource = clamp(legacyConfidence / 100, 0.50, 0.97);
  const dataFreshness = route.badge === 'scenario' ? -0.12 : route.badge === 'baseline' ? 0.03 : 0;
  const geopoliticalStability = clamp(1 - baseRisk / 260, 0.50, 1.0);
  const corridorDisruptionHistory = clamp(1 - baseRisk / 420, 0.60, 1.0);
  const routeComplexity = clamp(1 - (legCount - 1) * 0.018, 0.70, 1.0);
  const components = {
    geometrySource,
    dataFreshness,
    geopoliticalStability,
    corridorDisruptionHistory,
    routeComplexity,
  };
  return {
    score: computeConfidence(components),
    components,
    explanation: 'Multiplicative confidence model: geometry source ceiling, freshness, stability, disruption history, and route complexity.',
  };
}

export function formatConfidencePercent(value: number): string {
  return `${Math.round(value * 100)}%`;
}
