function parseObjectParam(value) {
  if (!value) return {};
  try {
    const parsed = JSON.parse(value);
    return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : {};
  } catch (_) {
    return {};
  }
}

function loadUrlState() {
  const params = new URLSearchParams(window.location.search);
  const chainId = params.get('chain');
  const routeId = params.get('route');
  const chain = CHAINS.find(function(item) { return item.id === chainId; }) || getChain();
  state.chainId = chain.id;
  const route = chain.routes.find(function(item) { return item.id === routeId; }) || chain.routes[0];
  state.routeId = route.id;
  state.mapMode = params.get('mode') === '3d' ? '3d' : '2d';

  const shocks = parseObjectParam(params.get('shocks'));
  Object.keys(state.shocks).forEach(function(key) {
    const value = Number(shocks[key]);
    if (Number.isFinite(value)) state.shocks[key] = Math.max(-50, Math.min(50, value));
  });

  const disruptions = (params.get('disruptions') || '').split(',').map(function(item) { return item.trim(); }).filter(Boolean);
  Object.keys(state.disruptions).forEach(function(key) {
    state.disruptions[key] = disruptions.includes(key);
  });

  const scenario = (params.get('scenario') || '').toLowerCase();
  if (scenario.includes('suez')) state.disruptions.suezClosure = true;
  if (scenario.includes('strike') || scenario.includes('port')) state.disruptions.portStrike = true;
  if (scenario.includes('sanction')) state.disruptions.sanctions = true;
  if (scenario.includes('weather')) state.disruptions.weather = true;

  document.body.classList.toggle('embed-mode', params.get('embed') === '1');
}

function syncUrlState() {
  const params = new URLSearchParams();
  params.set('chain', state.chainId);
  params.set('route', state.routeId);
  if (state.mapMode === '3d') params.set('mode', '3d');

  const activeShocks = {};
  Object.keys(state.shocks).forEach(function(key) {
    if (state.shocks[key] !== 0) activeShocks[key] = state.shocks[key];
  });
  if (Object.keys(activeShocks).length) params.set('shocks', JSON.stringify(activeShocks));

  const activeDisruptions = Object.keys(state.disruptions).filter(function(key) { return state.disruptions[key]; });
  if (activeDisruptions.length) params.set('disruptions', activeDisruptions.join(','));
  if (document.body.classList.contains('embed-mode')) params.set('embed', '1');

  const query = params.toString();
  const nextUrl = window.location.pathname + (query ? '?' + query : '') + window.location.hash;
  window.history.replaceState(null, '', nextUrl);
}

