function haversineKm(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) * Math.sin(dLon / 2) * Math.sin(dLon / 2);
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

function estimateTransitDays(from, to, mode) {
  const km = haversineKm(from.coords[0], from.coords[1], to.coords[0], to.coords[1]);
  const kpd = { air: 16000, sea: 720, rail: 600, road: 500 };
  return Math.max(0.2, km / (kpd[mode] || 500));
}

function drawIntelOverlays(route, scenario) {
  intelLayer.clearLayers();

  // Pulsing risk rings on high-risk destination nodes
  scenario.legs.forEach(function(leg, i) {
    if (leg.risk < 52) return;
    const node = route.nodes[i + 1];
    if (!node || !state.activeStages.has(node.stage)) return;
    const ringColor = leg.risk > 72 ? '#c94b4b' : '#f59e0b';
    L.marker(node.coords, {
      icon: L.divIcon({
        className: '',
        iconSize: [18, 18],
        iconAnchor: [9, 9],
        html: '<div class="risk-pulse-div" style="--ring-color:' + ringColor + '"></div>',
      }),
      interactive: false, keyboard: false,
    }).addTo(intelLayer);
  });

  // Bottleneck flag marker
  if (scenario.bottleneck) {
    const bnNode = scenario.bottleneck.to;
    if (bnNode && state.activeStages.has(bnNode.stage)) {
      L.marker(bnNode.coords, {
        icon: L.divIcon({
          className: '',
          iconSize: [28, 28],
          iconAnchor: [14, 28],
          popupAnchor: [0, -30],
          html: '<div class="intel-shell sev-critical" title="Bottleneck">ðŸ”´</div>',
        }),
        zIndexOffset: 500,
      }).bindPopup(
        '<h3 class="intel-popup-title">â›” Bottleneck Detected</h3>' +
        '<p class="intel-popup-body"><b>' + escapeHtml(bnNode.name) + '</b> is the highest-scoring bottleneck under current shock settings. Avg dwell ' + escapeHtml(bnNode.days[0] + 'â€“' + bnNode.days[1]) + 'd; bottleneck score is driven by combined time, risk, and confidence penalty.</p>' +
        '<div class="intel-popup-tags"><span class="intel-tag tag-active">âš¡ BOTTLENECK</span><span class="intel-tag tag-amber">' + escapeHtml(scenario.bottleneck.leg) + '</span></div>'
      ).addTo(intelLayer);
    }
  }

  // Chokepoint intelligence markers
  INTEL_CHOKEPOINTS.forEach(function(cp) {
    const isActive = cp.disruption && state.disruptions[cp.disruption];
    if (cp.sev === 'info' && !isActive) return;
    const sevClass = isActive ? 'sev-critical' : ('sev-' + cp.sev);
    const emoji = isActive ? 'âš¡' : (cp.sev === 'critical' ? 'âš ï¸' : 'â„¹ï¸');
    L.marker(cp.coords, {
      icon: L.divIcon({
        className: '',
        iconSize: [26, 26],
        iconAnchor: [13, 13],
        popupAnchor: [0, -16],
        html: '<div class="intel-shell ' + sevClass + '">' + emoji + '</div>',
      }),
      title: cp.label,
    }).bindPopup(
      '<h3 class="intel-popup-title">' + escapeHtml(cp.label) + '</h3>' +
      '<p class="intel-popup-body">' + escapeHtml(cp.desc) + '</p>' +
      '<div class="intel-popup-tags">' +
      cp.tags.map(function(t) { return '<span class="intel-tag tag-blue">' + escapeHtml(t) + '</span>'; }).join('') +
      (isActive ? '<span class="intel-tag tag-active">âš¡ ACTIVE DISRUPTION</span>' : '') +
      '</div>'
    ).addTo(intelLayer);
  });
}

