let globeInstance = null;

function riskToHex(risk, mode) {
  if (mode === 'air') return '#94c5e8';
  if (risk < 28) return '#3f8e6e';
  if (risk < 52) return '#f59e0b';
  return '#c94b4b';
}

function buildGlobeArcs() {
  const route = getRoute();
  const scenario = state.lastScenario && state.lastScenario.routeId === route.id
    ? state.lastScenario : runScenario(route);
  state.lastScenario = scenario;
  const arcs = [];
  for (let i = 1; i < route.nodes.length; i++) {
    if (!state.activeStages.has(route.nodes[i - 1].stage) || !state.activeStages.has(route.nodes[i].stage)) continue;
    const from = route.nodes[i - 1];
    const to = route.nodes[i];
    const mode = inferLegMode(from, to);
    const legResult = scenario.legs[i - 1];
    const risk = legResult ? legResult.risk : route.baseRisk;
    const isBottleneck = !!(scenario.bottleneck && scenario.bottleneck.index === i);
    const baseAlt = mode === 'air' ? 0.35 : mode === 'sea' ? 0.15 : 0.06;
    const baseTime = mode === 'air' ? 2000 : mode === 'sea' ? 3600 : 4800;
    const arcColor = isBottleneck ? '#ef4444' : riskToHex(risk, mode);
    const arcLabel = mode + ': ' + from.name + ' \u2192 ' + to.name;
    // Three parallel lanes per leg â€” staggered altitude and animation timing
    [0, 0.052, -0.052].forEach(function(altOff, lane) {
      arcs.push({
        id: 'arc_' + i + '_' + lane,
        startLat: from.coords[0], startLng: from.coords[1],
        endLat: to.coords[0], endLng: to.coords[1],
        mode, risk,
        color: arcColor,
        stroke: isBottleneck ? 0.80 : 0.28,
        altScale: baseAlt + altOff,
        animTime: baseTime * (1 + lane * 0.22),
        isBottleneck,
        label: lane === 0 ? arcLabel : '',
      });
    });
  }
  return arcs;
}

function buildGlobePoints() {
  const route = getRoute();
  return route.nodes
    .filter(function(node) { return state.activeStages.has(node.stage); })
    .map(function(node) {
      return {
        id: node.id,
        name: node.name,
        place: node.place,
        company: node.company,
        stage: node.stage,
        lat: node.coords[0],
        lng: node.coords[1],
        color: stageColor(node.stage),
      };
    });
}

function initGlobe() {
  if (globeInstance) return;
  globeInstance = Globe({ animateIn: true })
    .globeImageUrl('https://cdn.jsdelivr.net/npm/three-globe/example/img/earth-night.jpg')
    .bumpImageUrl('https://cdn.jsdelivr.net/npm/three-globe/example/img/earth-topology.png')
    .backgroundColor('#0e1118')
    .showAtmosphere(true)
    .atmosphereColor('#2374ab')
    .atmosphereAltitude(0.18)
    .arcStroke(function(d) { return d.stroke; })
    .arcAltitude(function(d) { return d.altScale; })
    .arcDashLength(0.14)
    .arcDashGap(0.86)
    .arcDashAnimateTime(function(d) { return d.animTime; })
    .arcColor(function(d) { return d.color; })
    .arcLabel(function(d) { return '<div style="font-family:monospace;font-size:11px;background:rgba(14,17,24,0.88);padding:5px 8px;border-radius:6px;border:1px solid #2a3a55;color:#dde4ef">' + escapeHtml(d.label) + '<br/><span style="color:#7a8ba0">risk ' + Math.round(d.risk) + ' | ' + d.mode + '</span></div>'; })
    .pointColor(function(d) { return d.color; })
    .pointAltitude(0.015)
    .pointRadius(0.42)
    .pointLabel(function(d) {
      return '<div style="font-family:monospace;font-size:11px;background:rgba(14,17,24,0.88);padding:5px 8px;border-radius:6px;border:1px solid #2a3a55;color:#dde4ef"><b>' + escapeHtml(d.name) + '</b><br/>' + escapeHtml(d.place) + '<br/><span style="color:#7a8ba0">' + escapeHtml(d.company) + '</span></div>';
    })
    .onPointClick(function(d) {
      const nodeBtn = document.querySelector('[data-node-id="' + d.id + '"]');
      if (nodeBtn) nodeBtn.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
    })
    .labelsData([])
    .labelLat(function(d) { return d.lat; })
    .labelLng(function(d) { return d.lng; })
    .labelText(function(d) { return d.name; })
    .labelSize(0.48)
    .labelDotRadius(0)
    .labelColor(function() { return 'rgba(221,228,239,0.82)'; })
    .labelResolution(2)
    .labelAltitude(0.04)
    (document.getElementById('globe'));
  globeInstance.controls().autoRotate = true;
  globeInstance.controls().autoRotateSpeed = 0.28;
  globeInstance.controls().enableDamping = true;
}

function drawGlobe() {
  initGlobe();
  // Clear previous chain's data synchronously to prevent stale nodes
  globeInstance.arcsData([]).pointsData([]).labelsData([]);
  const arcs = buildGlobeArcs();
  const points = buildGlobePoints();
  globeInstance.arcsData(arcs).pointsData(points).labelsData(points);
  const route = getRoute();
  if (route.nodes.length) {
    const avgLat = route.nodes.reduce(function(s, n) { return s + n.coords[0]; }, 0) / route.nodes.length;
    const avgLng = route.nodes.reduce(function(s, n) { return s + n.coords[1]; }, 0) / route.nodes.length;
    const spread = Math.max.apply(null, route.nodes.map(function(n) {
      return Math.abs(n.coords[1] - avgLng) + Math.abs(n.coords[0] - avgLat);
    }));
    const alt = Math.max(1.2, Math.min(3.5, spread / 55));
    globeInstance.pointOfView({ lat: avgLat, lng: avgLng, altitude: alt }, 1400);
  }
  // Phase-2 hook: expose the live globe + arcs/points + current route
  // so the enhancement module (src/map/globeMap.ts) can layer chokepoint
  // rings, dynamic dash speeds, and fly-to-chain framing.
  try {
    (window as any).__heimdallGlobe = globeInstance;
    (window as any).__heimdallGlobeContext = { arcs: arcs, points: points, route: route };
    window.dispatchEvent(new CustomEvent('heimdall:globe-rendered', { detail: { arcs: arcs, points: points, route: route } }));
  } catch (_e) { /* ignore */ }
}
