function generateLocalRecommendations() {
  const route = getRoute();
  const recs = [];
  const nodes = route.nodes;

  // Find the slowest node as the bottleneck
  let maxDays = 0, bnIdx = 1;
  for (let i = 1; i < nodes.length; i++) {
    const d = averageDays(nodes[i]);
    if (d > maxDays) { maxDays = d; bnIdx = i; }
  }
  const bn = nodes[bnIdx];
  const prev = nodes[bnIdx - 1] || nodes[0];
  const mode = inferLegMode(prev, bn);
  const sev = severityForLeg(mode);

  recs.push({
    priority: sev > 0.4 ? 'critical' : 'high',
    type: 'bottleneck',
    legId: 'leg-' + bnIdx,
    mode,
    from: prev.name,
    to: bn.name,
    issue: bn.name + ' is the slowest node (avg ' + averageDays(bn).toFixed(1) + 'd). This leg dominates chain lead time under current conditions.',
    suggestion: 'Consider pre-positioning inventory at ' + bn.name + ' or negotiating a dedicated carrier allocation to buffer this delay.',
    delta: { timeHours: 0, costUsd: 0, riskChange: 0 },
  });

  if (state.disruptions.suezClosure) {
    recs.push({
      priority: 'critical',
      type: 'corridor_bypass',
      legId: 'suez-impact',
      mode: 'sea',
      from: 'Origin port',
      to: 'Destination port',
      issue: 'Suez Canal closure adds 8â€“14 days to all affected sea legs. Congestion at alternative ports compounds the delay.',
      suggestion: 'Route via Cape of Good Hope (+10d, +$15k) or use air cargo for time-critical units. Source regionally if possible.',
      delta: { timeHours: 240, costUsd: 15000, riskChange: -18 },
    });
  }

  if (state.shocks.congestion > 25) {
    recs.push({
      priority: 'medium',
      type: 'mode_substitution',
      legId: 'congestion-road',
      mode: 'road',
      from: 'Origin',
      to: 'Destination',
      issue: 'Congestion shock at ' + state.shocks.congestion + '% is extending road transit windows across all land legs.',
      suggestion: 'Rail absorbs congestion shocks better and may save 20â€“30% cost on lanes over 500 km.',
      delta: { timeHours: Math.round(state.shocks.congestion * 0.9), costUsd: -9000, riskChange: -4 },
    });
  }

  if (state.shocks.fuel > 30) {
    recs.push({
      priority: 'medium',
      type: 'cost_hedge',
      legId: 'fuel-exposure',
      mode: 'sea',
      from: 'Origin',
      to: 'Destination',
      issue: 'Fuel shock at +' + state.shocks.fuel + '% is materially lifting sea and air freight costs on this chain.',
      suggestion: 'Lock in forward freight contracts or negotiate fuel-neutral rates with carriers to contain cost volatility.',
      delta: { timeHours: 0, costUsd: -Math.round(state.shocks.fuel * 400), riskChange: -2 },
    });
  }

  return recs;
}

function renderRecommendations(data) {
  const recs = data.recommendations || [];
  el.recResults.classList.add('visible');
  if (recs.length === 0) {
    el.recCards.innerHTML = '<div class="empty-state" style="font-size:11px;padding:8px 10px">No critical recommendations for the current configuration.</div>';
    return;
  }
  el.recCards.innerHTML = recs.map(function(rec) {
    const dTime = rec.delta.timeHours;
    const dCost = rec.delta.costUsd;
    const dRisk = rec.delta.riskChange;
    function deltaClass(v) { return v > 0 ? 'pos' : v < 0 ? 'neg' : 'zero'; }
    function timeLabel(v) { return v === 0 ? 'â€”h' : (v > 0 ? '+' : '') + v + 'h'; }
    function costLabel(v) { return v === 0 ? 'â€”' : (v > 0 ? '+$' : '-$') + Math.abs(v).toLocaleString(); }
    function riskLabel(v) { return v === 0 ? 'â€”' : (v > 0 ? '+' : '') + v + ' risk'; }
    return '<div class="rec-card ' + rec.priority + '">' +
      '<div class="rec-header">' +
        '<span class="rec-priority ' + rec.priority + '">' + rec.priority + '</span>' +
        '<span class="rec-leg" title="' + escapeHtml(rec.from + ' â†’ ' + rec.to) + '">' + escapeHtml(rec.from) + ' â†’ ' + escapeHtml(rec.to) + '</span>' +
      '</div>' +
      '<div class="rec-issue">' + escapeHtml(rec.issue) + '</div>' +
      '<div class="rec-suggestion">' + escapeHtml(rec.suggestion) + '</div>' +
      '<div class="rec-deltas">' +
        '<span class="rec-delta ' + deltaClass(dTime) + '">' + timeLabel(dTime) + '</span>' +
        '<span class="rec-delta ' + deltaClass(dCost) + '">' + costLabel(dCost) + '</span>' +
        '<span class="rec-delta ' + deltaClass(dRisk) + '">' + riskLabel(dRisk) + '</span>' +
      '</div>' +
    '</div>';
  }).join('');
}

