function generateLocalFrontier() {
  const route = getRoute();
  const baseDays = routeBaseDays(route);
  const oilLevels = [60, 75, 83, 95, 110, 130];
  const ctnLevels = [0.75, 1.0, 1.25, 1.5, 2.0];
  const geoLevels = [0.15, 0.30, 0.45, 0.60];
  const pts = [];
  oilLevels.forEach(function(oil) {
    ctnLevels.forEach(function(ctn) {
      geoLevels.forEach(function(geo) {
        const tMult = 1 + Math.max(0, ctn - 1) * 0.55 + geo * 0.08;
        const cMult = 1 + Math.max(-0.45, (oil - 83) / 83) * 0.30 + Math.max(0, ctn - 1) * 0.45;
        pts.push({
          totalHours: baseDays * 24 * tMult,
          totalCostUsd: 85000 * cMult,
          riskScore: geo * 55 + 0.30 * 35,
          isPareto: false,
        });
      });
    });
  });
  pts.forEach(function(pt) {
    pt.isPareto = !pts.some(function(o) {
      return o !== pt &&
        o.totalHours <= pt.totalHours && o.totalCostUsd <= pt.totalCostUsd &&
        (o.totalHours < pt.totalHours || o.totalCostUsd < pt.totalCostUsd);
    });
  });
  return { pointCount: pts.length, paretoCount: pts.filter(function(p) { return p.isPareto; }).length, points: pts };
}

function renderFrontier(data) {
  const pts = data.points || [];
  el.frontierResults.classList.add('visible');
  el.frontierLabel.textContent = data.paretoCount + ' Pareto-optimal / ' + data.pointCount + ' scenarios';
  const W = 240, H = 130, PX = 26, PY = 14;
  if (!pts.length) { el.frontierSvg.innerHTML = ''; return; }
  const minH = Math.min.apply(null, pts.map(function(p) { return p.totalHours; }));
  const maxH = Math.max.apply(null, pts.map(function(p) { return p.totalHours; }));
  const minC = Math.min.apply(null, pts.map(function(p) { return p.totalCostUsd; }));
  const maxC = Math.max.apply(null, pts.map(function(p) { return p.totalCostUsd; }));
  function sx(p) { return PX + (p.totalHours - minH) / (maxH - minH || 1) * (W - PX - 8); }
  function sy(p) { return H - PY - (p.totalCostUsd - minC) / (maxC - minC || 1) * (H - PY - 10); }
  function riskHex(r) { return r < 25 ? '#3f8e6e' : r < 45 ? '#f59e0b' : '#c94b4b'; }
  let inner = '<line x1="' + PX + '" y1="8" x2="' + PX + '" y2="' + (H - PY) + '" stroke="#d9dee5" stroke-width="1"/>';
  inner += '<line x1="' + PX + '" y1="' + (H - PY) + '" x2="' + (W - 4) + '" y2="' + (H - PY) + '" stroke="#d9dee5" stroke-width="1"/>';
  inner += '<text x="' + (PX - 3) + '" y="14" text-anchor="end" font-size="8" fill="#66717f">Cost</text>';
  inner += '<text x="' + (W - 4) + '" y="' + (H - 2) + '" text-anchor="end" font-size="8" fill="#66717f">Time â†’</text>';
  pts.filter(function(p) { return !p.isPareto; }).forEach(function(p) {
    inner += '<circle cx="' + sx(p).toFixed(1) + '" cy="' + sy(p).toFixed(1) + '" r="2" fill="' + riskHex(p.riskScore) + '" opacity="0.28"/>';
  });
  const pareto = pts.filter(function(p) { return p.isPareto; }).sort(function(a, b) { return a.totalHours - b.totalHours; });
  if (pareto.length > 1) {
    const path = 'M' + pareto.map(function(p) { return sx(p).toFixed(1) + ',' + sy(p).toFixed(1); }).join(' L');
    inner += '<path d="' + path + '" fill="none" stroke="#2374ab" stroke-width="1.2" stroke-dasharray="4,2" opacity="0.65"/>';
  }
  pareto.forEach(function(p) {
    inner += '<circle cx="' + sx(p).toFixed(1) + '" cy="' + sy(p).toFixed(1) + '" r="3.5" fill="' + riskHex(p.riskScore) + '" stroke="#fff" stroke-width="1.5"/>';
  });
  el.frontierSvg.innerHTML = inner;
}

function adjustedMetrics(route) {
  const result = runScenario(route);
  state.lastScenario = result;
  return {
    base: result.totalBaseDays,
    adjusted: result.totalAdjustedDays,
    risk: Math.round(result.totalRisk),
    confidence: Math.round(result.confidence),
    cost: Math.round(result.totalAdjustedCost / Math.max(1, result.legs.length)),
  };
}

// Phase 2 API blueprint implemented in-browser so frontend logic is transportable to backend endpoints.
const heimdallScenarioApi = {
  getChains: function() {
    return CHAINS.map(function(chain) {
      return {
        chainId: chain.id,
        title: chain.title,
        category: chain.category,
        routeCount: chain.routes.length,
      };
    });
  },
  getChain: function(chainId) {
    const chain = CHAINS.find(function(item) { return item.id === chainId; });
    if (!chain) return null;
    return {
      chainId: chain.id,
      title: chain.title,
      category: chain.category,
      routes: chain.routes.map(function(route) {
        return {
          routeId: route.id,
          name: route.name,
          nodes: route.nodes.length,
        };
      }),
    };
  },
  run: function(input) {
    if (input && typeof input.chainId === 'string' && input.chainId !== state.chainId) {
      const target = CHAINS.find(function(chain) { return chain.id === input.chainId; });
      if (target) {
        state.chainId = target.id;
        state.routeId = target.routes[0].id;
      }
    }
    if (input && typeof input.routeId === 'string') {
      const route = getChain().routes.find(function(item) { return item.id === input.routeId; });
      if (route) state.routeId = route.id;
    }
    if (input && input.shocks) {
      Object.keys(state.shocks).forEach(function(key) {
        if (typeof input.shocks[key] === 'number') state.shocks[key] = input.shocks[key];
      });
    }
    if (input && input.disruptions) {
      Object.keys(state.disruptions).forEach(function(key) {
        if (typeof input.disruptions[key] === 'boolean') state.disruptions[key] = input.disruptions[key];
      });
    }
    state.lastScenario = null;
    const result = runScenario(getRoute());
    state.lastScenario = result;
    return result;
  },
};
window.heimdallScenarioApi = heimdallScenarioApi;

function shortDays(days) {
  if (days >= 100) return Math.round(days) + 'd';
  return Math.round(days * 10) / 10 + 'd';
}

function escapeHtml(value) {
  return String(value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function allTextForChain(chain) {
  const routeText = chain.routes.flatMap((route) => [
    route.name,
    route.description,
    ...route.nodes.flatMap((node) => [node.name, node.place, node.company, node.process]),
  ]);
  return [
    chain.title,
    chain.category,
    chain.summary,
    ...chain.aliases,
    ...chain.taxonomy.inputs,
    ...chain.taxonomy.middleputs,
    ...chain.taxonomy.outputs,
    ...routeText,
  ].join(' ').toLowerCase();
}

function searchChains(query) {
  const needle = query.trim().toLowerCase();
  if (!needle) {
    return CHAINS.slice(0, 5).map((chain) => ({ chain, reason: 'featured' }));
  }
  return CHAINS
    .map((chain) => {
      const exactAlias = chain.aliases.find((alias) => alias.toLowerCase() === needle);
      const partialAlias = chain.aliases.find((alias) => alias.toLowerCase().includes(needle));
      const taxonomyHit = [...chain.taxonomy.inputs, ...chain.taxonomy.middleputs, ...chain.taxonomy.outputs]
        .find((item) => item.toLowerCase().includes(needle));
      const textHit = allTextForChain(chain).includes(needle);
      if (!exactAlias && !partialAlias && !taxonomyHit && !textHit) return null;
      return { chain, reason: exactAlias || partialAlias || taxonomyHit || 'route/company hit' };
    })
    .filter(Boolean)
    .slice(0, 6);
}

function setChain(chainId) {
  const chain = CHAINS.find((item) => item.id === chainId);
  if (!chain) return;
  state.chainId = chain.id;
  state.routeId = chain.routes[0].id;
  state.lastScenario = null;
  render();
  fitToRoute();
  syncUrlState();
}

function setRoute(routeId) {
  const route = getChain().routes.find((item) => item.id === routeId);
  if (!route) return;
  state.routeId = routeId;
  state.lastScenario = null;
  render();
  fitToRoute();
  syncUrlState();
}

function focusNode(nodeId) {
  let match = null;
  CHAINS.some(function(chain) {
    return chain.routes.some(function(route) {
      const node = route.nodes.find(function(item) { return item.id === nodeId; });
      if (!node) return false;
      match = { chain: chain, route: route, node: node };
      return true;
    });
  });
  if (!match) return;
  state.chainId = match.chain.id;
  state.routeId = match.route.id;
  state.lastScenario = null;
  render();
  syncUrlState();
  window.setTimeout(function() {
    if (state.mapMode === '2d') {
      const marker = state.markersByNode.get(nodeId);
      if (marker) {
        map.setView(marker.getLatLng(), Math.max(map.getZoom(), 5), { animate: true });
        marker.openPopup();
      } else {
        map.setView(match.node.coords, Math.max(map.getZoom(), 5), { animate: true });
      }
    } else if (globeInstance) {
      globeInstance.pointOfView({ lat: match.node.coords[0], lng: match.node.coords[1], altitude: 1.15 }, 1200);
    }
  }, 80);
}

function fitToRoute() {
  const route = getRoute();
  const visible = route.nodes.filter((node) => state.activeStages.has(node.stage));
  const points = visible.length ? visible : route.nodes;
  const bounds = L.latLngBounds(points.map((node) => node.coords));
  if (bounds.isValid()) {
    map.fitBounds(bounds, { paddingTopLeft: [390, 92], paddingBottomRight: [410, 142], maxZoom: 5.5 });
  }
}

function stageColor(stage) {
  return STAGES[stage]?.color || '#66717f';
}

function markerForNode(node) {
  const dwellStr = node.days[0] + '\u2013' + node.days[1] + 'd';
  const color = stageColor(node.stage);
  return L.divIcon({
    className: '',
    iconSize: [50, 52],
    iconAnchor: [17, 17],
    popupAnchor: [0, -26],
    html: '<div class="node-marker-wrap">' +
      '<div class="node-marker-shell" style="--stage-color:' + color + '">' + escapeHtml(node.code) + '</div>' +
      '<div class="node-dwell-badge" style="background:' + color + '">' + escapeHtml(dwellStr) + '</div>' +
      '</div>',
  });
}

function drawMap() {
  if (state.mapMode === '3d') { drawGlobe(); return; }
  const gen = ++drawGeneration;
  routeLayer.clearLayers();
  state.markersByNode.clear();
  const route = getRoute();
  const scenario = state.lastScenario && state.lastScenario.routeId === route.id ? state.lastScenario : runScenario(route);
  state.lastScenario = scenario;
  const bottleneckIndex = scenario.bottleneck ? scenario.bottleneck.index : -1;

  // Draw markers synchronously so they're immediately visible
  route.nodes.forEach(function(node) {
    if (!state.activeStages.has(node.stage)) return;
    const popup = [
      '<h3 class="popup-title">' + escapeHtml(node.name) + '</h3>',
      '<p class="popup-meta"><b>' + escapeHtml(STAGES[node.stage].label) + '</b> | ' + escapeHtml(node.place) + '<br />' + escapeHtml(node.company) + '<br />' + escapeHtml(node.process) + '</p>',
    ].join('');
    const marker = L.marker(node.coords, { icon: markerForNode(node), title: node.name })
      .bindPopup(popup)
      .addTo(routeLayer);
    state.markersByNode.set(node.id, marker);
  });

  // Fetch and progressively draw snapped route segments
  (async function() {
    for (let index = 1; index < route.nodes.length; index += 1) {
      if (gen !== drawGeneration) return;
      const prev = route.nodes[index - 1];
      const node = route.nodes[index];
      if (!state.activeStages.has(prev.stage) || !state.activeStages.has(node.stage)) continue;
      const mode = inferLegMode(prev, node);
      const isBottleneck = index === bottleneckIndex;
      const color = stageColor(node.stage);
      const coords = await getSegmentGeom(prev, node, mode);
      if (gen !== drawGeneration) return;
      L.polyline(coords, {
        color: isBottleneck ? '#c94b4b' : color,
        weight: isBottleneck ? 7 : 5,
        opacity: isBottleneck ? 0.98 : 0.82,
        smoothFactor: 1.1,
        className: isBottleneck ? '' : 'route-segment',
      }).addTo(routeLayer);

      // Transit time label on path midpoint (travel time estimate, not node dwell)
      const transitDays = estimateTransitDays(prev, node, mode);
      const midIdx = Math.floor(coords.length / 2);
      const midPt = coords[midIdx] || [(prev.coords[0] + node.coords[0]) / 2, (prev.coords[1] + node.coords[1]) / 2];
      const segColor = isBottleneck ? '#c94b4b' : color;
      L.marker(midPt, {
        icon: L.divIcon({
          className: 'path-time-label',
          html: '<span class="transit-pill" style="background:' + segColor + ';opacity:0.88">~' + shortDays(transitDays) + ' transit</span>',
          iconAnchor: [40, 10],
          iconSize: null,
        }),
        interactive: false, keyboard: false,
      }).addTo(routeLayer);
    }
  })();

  // Intelligence overlays (risk pulses, chokepoints, bottleneck flag)
  drawIntelOverlays(route, scenario);
}

