function inferLegMode(from, to) {
  if (from.code === 'PORT' && to.code === 'PORT') return 'sea';
  if (from.code === 'AIR' || to.code === 'AIR') return 'air';
  if (from.code === 'RAIL' || to.code === 'RAIL' || to.code === 'PORT' || from.code === 'PORT') return 'rail';
  return 'road';
}

function routeSourceForMode(mode) {
  if (mode === 'sea') return 'maritime corridor graph';
  if (mode === 'rail') return 'OSRM road approx.';
  if (mode === 'air') return 'great-circle arc';
  return 'OSRM road network';
}

