async function fetchOSRM(fromNode, toNode) {
  const controller = new AbortController();
  const timer = setTimeout(function() { controller.abort(); }, 8000);
  try {
    const url = 'https://router.project-osrm.org/route/v1/driving/'
      + fromNode.coords[1] + ',' + fromNode.coords[0] + ';'
      + toNode.coords[1] + ',' + toNode.coords[0]
      + '?overview=full&geometries=geojson';
    const resp = await fetch(url, { signal: controller.signal });
    clearTimeout(timer);
    if (!resp.ok) return null;
    const data = await resp.json();
    if (data.routes && data.routes[0]) {
      return data.routes[0].geometry.coordinates.map(function(c) { return [c[1], c[0]]; });
    }
  } catch (_) { clearTimeout(timer); }
  return null;
}

