function wpDist(a, b) {
  const R = 6371, r = Math.PI / 180;
  const dLat = (b[0] - a[0]) * r, dLon = (b[1] - a[1]) * r;
  const x = Math.sin(dLat / 2) ** 2 + Math.cos(a[0] * r) * Math.cos(b[0] * r) * Math.sin(dLon / 2) ** 2;
  return R * 2 * Math.atan2(Math.sqrt(x), Math.sqrt(1 - x));
}

function nearestWP(coords) {
  let best = null, bestD = Infinity;
  for (const [id, wp] of Object.entries(SEA_WP)) {
    const d = wpDist(coords, wp);
    if (d < bestD) { bestD = d; best = id; }
  }
  return best;
}

function seaDijkstra(fromCoords, toCoords) {
  const startId = nearestWP(fromCoords);
  const endId = nearestWP(toCoords);
  if (startId === endId) return [fromCoords, SEA_WP[startId], toCoords];

  const adj = {};
  for (const id of Object.keys(SEA_WP)) adj[id] = [];
  for (const [a, b] of SEA_EDGES) { adj[a].push(b); adj[b].push(a); }

  const dist = {}, prev = {}, visited = new Set();
  for (const id of Object.keys(SEA_WP)) dist[id] = Infinity;
  dist[startId] = 0;
  const pq = [[0, startId]];
  while (pq.length) {
    pq.sort(function(a, b) { return a[0] - b[0]; });
    const [d, u] = pq.shift();
    if (visited.has(u)) continue;
    visited.add(u);
    if (u === endId) break;
    for (const v of adj[u]) {
      const w = d + wpDist(SEA_WP[u], SEA_WP[v]);
      if (w < dist[v]) { dist[v] = w; prev[v] = u; pq.push([w, v]); }
    }
  }

  const path = [];
  let cur = endId;
  while (cur) { path.unshift(SEA_WP[cur]); cur = prev[cur]; }
  return path.length ? [fromCoords, ...path, toCoords] : [fromCoords, toCoords];
}

function arcPoints(from, to, steps) {
  const pts = [], r = Math.PI / 180;
  const lat1 = from[0] * r, lon1 = from[1] * r;
  const lat2 = to[0] * r, lon2 = to[1] * r;
  const d = 2 * Math.asin(Math.sqrt(
    Math.sin((lat2 - lat1) / 2) ** 2 + Math.cos(lat1) * Math.cos(lat2) * Math.sin((lon2 - lon1) / 2) ** 2
  ));
  for (let i = 0; i <= steps; i++) {
    if (d < 0.0001) { pts.push([from[0], from[1]]); continue; }
    const f = i / steps;
    const A = Math.sin((1 - f) * d) / Math.sin(d), B = Math.sin(f * d) / Math.sin(d);
    const x = A * Math.cos(lat1) * Math.cos(lon1) + B * Math.cos(lat2) * Math.cos(lon2);
    const y = A * Math.cos(lat1) * Math.sin(lon1) + B * Math.cos(lat2) * Math.sin(lon2);
    const z = A * Math.sin(lat1) + B * Math.sin(lat2);
    pts.push([Math.atan2(z, Math.sqrt(x * x + y * y)) / r, Math.atan2(y, x) / r]);
  }
  return pts;
}

async function getSegmentGeom(fromNode, toNode, mode) {
  const key = geomCacheKey(fromNode, toNode, mode);
  if (routeGeomCache.has(key)) return routeGeomCache.get(key);
  const stored = loadStoredGeom(key);
  if (stored) { routeGeomCache.set(key, stored); return stored; }

  let coords;
  if (mode === 'road' || mode === 'rail') {
    coords = await fetchOSRM(fromNode, toNode) || [fromNode.coords, toNode.coords];
  } else if (mode === 'sea') {
    coords = seaDijkstra(fromNode.coords, toNode.coords);
  } else if (mode === 'air') {
    coords = arcPoints(fromNode.coords, toNode.coords, 32);
  } else {
    coords = [fromNode.coords, toNode.coords];
  }
  routeGeomCache.set(key, coords);
  saveStoredGeom(key, coords);
  return coords;
}

