import { CHAINS, INTEL_CHOKEPOINTS } from '../data/uiConstants.js';
import { loadGlossary } from '../glossary/glossaryEngine.js';
import type { GlossaryTerm } from '../glossary/glossaryEngine.js';

type ResultKind = 'chain' | 'route' | 'node' | 'glossary' | 'chokepoint';

interface PaletteResult {
  kind: ResultKind;
  icon: string;
  title: string;
  subtitle: string;
  badge: string;
  action: () => void;
}

const KIND_LABEL: Record<ResultKind, string> = {
  chain: 'Chain',
  route: 'Route',
  node: 'Node',
  glossary: 'Glossary',
  chokepoint: 'Chokepoint',
};

let root: HTMLElement | null = null;
let input: HTMLInputElement | null = null;
let list: HTMLElement | null = null;
let open = false;
let activeIndex = 0;
let results: PaletteResult[] = [];
let debounceHandle: number | null = null;
let querySeq = 0;

function escapeHtml(value: string): string {
  return value
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function appApi(): any {
  return (window as any).__heimdallApi ?? {};
}

function searchableText(parts: Array<string | undefined | null>): string {
  return parts.filter(Boolean).join(' ').toLowerCase();
}

function glossaryTermIdForChokepoint(id: string): string {
  return `chokepoint_${id.replace(/-/g, '_')}`;
}

function openGlossaryTerm(termId: string): void {
  window.dispatchEvent(new CustomEvent('heimdall:open-glossary-term', { detail: { termId } }));
}

function flattenStaticResults(query: string): PaletteResult[] {
  const needle = query.trim().toLowerCase();
  const out: PaletteResult[] = [];
  const chains = CHAINS as any[];
  const chokepoints = INTEL_CHOKEPOINTS as any[];

  for (const chain of chains) {
    const chainText = searchableText([
      chain.title,
      chain.category,
      chain.summary,
      ...(chain.aliases ?? []),
      ...(chain.taxonomy?.inputs ?? []),
      ...(chain.taxonomy?.middleputs ?? []),
      ...(chain.taxonomy?.outputs ?? []),
    ]);
    if (!needle || chainText.includes(needle)) {
      out.push({
        kind: 'chain',
        icon: 'network',
        title: chain.title,
        subtitle: chain.summary,
        badge: chain.category,
        action: () => appApi().setChain?.(chain.id),
      });
    }

    for (const route of chain.routes ?? []) {
      const routeText = searchableText([route.name, route.description, route.badge, route.traffic?.bottleneck]);
      if (needle && routeText.includes(needle)) {
        out.push({
          kind: 'route',
          icon: 'route',
          title: route.name,
          subtitle: `${chain.title} · ${route.description}`,
          badge: route.badge ?? 'route',
          action: () => {
            appApi().setChain?.(chain.id);
            window.setTimeout(() => appApi().setRoute?.(route.id), 20);
          },
        });
      }

      for (const node of route.nodes ?? []) {
        const nodeText = searchableText([node.name, node.place, node.company, node.process, node.stage, node.code]);
        if (needle && nodeText.includes(needle)) {
          out.push({
            kind: 'node',
            icon: 'map-pin',
            title: node.name,
            subtitle: `${node.company} · ${node.place}`,
            badge: chain.title,
            action: () => appApi().focusNode?.(node.id),
          });
        }
      }
    }
  }

  for (const chokepoint of chokepoints) {
    const text = searchableText([chokepoint.label, chokepoint.desc, chokepoint.sev, ...(chokepoint.tags ?? [])]);
    if (needle && text.includes(needle)) {
      out.push({
        kind: 'chokepoint',
        icon: 'radar',
        title: chokepoint.label,
        subtitle: chokepoint.desc,
        badge: chokepoint.sev,
        action: () => openGlossaryTerm(glossaryTermIdForChokepoint(chokepoint.id)),
      });
    }
  }

  return out;
}

function resultHtml(result: PaletteResult, index: number): string {
  const active = index === activeIndex ? ' active' : '';
  return `
    <button type="button" class="cmdk-result${active}" data-cmdk-index="${index}">
      <span class="cmdk-icon"><i data-lucide="${escapeHtml(result.icon)}"></i></span>
      <span class="cmdk-copy">
        <strong>${escapeHtml(result.title)}</strong>
        <span>${escapeHtml(result.subtitle)}</span>
      </span>
      <span class="cmdk-badge">${escapeHtml(result.badge || KIND_LABEL[result.kind])}</span>
    </button>`;
}

function render(): void {
  if (!list) return;
  if (!results.length) {
    list.innerHTML = '<div class="cmdk-empty">No matches.</div>';
    return;
  }
  list.innerHTML = results.slice(0, 14).map(resultHtml).join('');
  list.querySelectorAll<HTMLButtonElement>('[data-cmdk-index]').forEach((button) => {
    button.addEventListener('click', () => {
      const index = Number(button.dataset.cmdkIndex ?? 0);
      activate(index);
    });
  });
  (window as any).lucide?.createIcons?.();
}

async function updateResults(): Promise<void> {
  const seq = ++querySeq;
  const query = input?.value ?? '';
  const staticResults = flattenStaticResults(query);
  let glossaryResults: PaletteResult[] = [];
  if (query.trim().length >= 2) {
    const glossary = await loadGlossary();
    if (seq !== querySeq) return;
    glossaryResults = glossary.search(query, 8).map((term: GlossaryTerm) => ({
      kind: 'glossary',
      icon: 'book-open',
      title: term.term,
      subtitle: term.shortDef,
      badge: term.category.replace(/_/g, ' '),
      action: () => openGlossaryTerm(term.id),
    }));
  }
  results = [...staticResults, ...glossaryResults].slice(0, 40);
  activeIndex = Math.min(activeIndex, Math.max(0, results.length - 1));
  render();
}

function debouncedUpdate(): void {
  if (debounceHandle !== null) window.clearTimeout(debounceHandle);
  debounceHandle = window.setTimeout(() => { void updateResults(); }, 100);
}

function activate(index: number): void {
  const result = results[index];
  if (!result) return;
  closePalette();
  result.action();
}

function openPalette(): void {
  if (!root || !input) return;
  open = true;
  activeIndex = 0;
  root.classList.add('open');
  input.value = '';
  void updateResults();
  window.setTimeout(() => input?.focus(), 20);
}

function closePalette(): void {
  if (!root) return;
  open = false;
  root.classList.remove('open');
}

function moveActive(delta: number): void {
  if (!results.length) return;
  activeIndex = (activeIndex + delta + Math.min(results.length, 14)) % Math.min(results.length, 14);
  render();
  list?.querySelector(`[data-cmdk-index="${activeIndex}"]`)?.scrollIntoView({ block: 'nearest' });
}

function createMarkup(): void {
  root = document.createElement('div');
  root.className = 'cmdk-shell';
  root.innerHTML = `
    <div class="cmdk-backdrop" data-cmdk-close></div>
    <section class="cmdk-panel" role="dialog" aria-modal="true" aria-label="Command palette">
      <div class="cmdk-search-row">
        <i data-lucide="search"></i>
        <input id="cmdkInput" type="search" autocomplete="off" spellcheck="false" placeholder="Search chains, nodes, chokepoints, glossary..." />
        <span class="cmdk-kbd">Esc</span>
      </div>
      <div class="cmdk-list" id="cmdkList"></div>
    </section>`;
  document.body.appendChild(root);
  input = root.querySelector<HTMLInputElement>('#cmdkInput');
  list = root.querySelector<HTMLElement>('#cmdkList');
  input?.addEventListener('input', debouncedUpdate);
  root.querySelector('[data-cmdk-close]')?.addEventListener('click', closePalette);
}

export function initCommandPalette(): void {
  if (root) return;
  createMarkup();

  document.addEventListener('keydown', (event) => {
    const isCommand = (event.ctrlKey || event.metaKey) && event.key.toLowerCase() === 'k';
    if (isCommand) {
      event.preventDefault();
      openPalette();
      return;
    }
    if (!open) return;
    if (event.key === 'Escape') {
      event.preventDefault();
      closePalette();
    } else if (event.key === 'ArrowDown') {
      event.preventDefault();
      moveActive(1);
    } else if (event.key === 'ArrowUp') {
      event.preventDefault();
      moveActive(-1);
    } else if (event.key === 'Enter') {
      event.preventDefault();
      activate(activeIndex);
    }
  });
}
