/*
 * src/map/globeMap.ts — Phase 2 globe enhancements layered on top of the
 * legacy `initGlobe` / `drawGlobe` defined in src/app.ts.
 *
 * The legacy code dispatches `heimdall:globe-rendered` after each render
 * and exposes the live Globe.gl instance via `window.__heimdallGlobe`.
 * This module attaches:
 *   - chokepoint ring layer with severity colour ramp
 *   - leg-duration-tied dash animation speed (slower = longer duration)
 *   - shock-aware arc colour shift toward red under active disruption
 *   - bbox-driven fly-to-chain framing on render
 */
import { INTEL_CHOKEPOINTS } from '../data/uiConstants.js';

interface GlobeArcLike {
  startLat: number;
  startLng: number;
  endLat: number;
  endLng: number;
  color?: string;
  stroke?: number;
  altScale?: number;
  animTime?: number;
  label?: string;
  risk?: number;
  mode?: string;
  // fields we may inject when source legs carry the data
  hours?: number;
  legId?: string;
  shocked?: boolean;
}

interface RouteLike {
  nodes: Array<{ id?: string; coords: [number, number] }>;
}

interface RenderDetail {
  arcs: GlobeArcLike[];
  points: Array<{ lat: number; lng: number }>;
  route: RouteLike;
}

interface ChokepointRing {
  lat: number;
  lng: number;
  maxR: number;
  propagationSpeed: number;
  repeatPeriod: number;
  color: () => string;
  __id: string;
  __label: string;
  __sev: string;
  __desc: string;
}

const SEV_RING_COLOR: Record<string, string> = {
  critical: 'rgba(220, 70, 70, 0.55)',
  warning: 'rgba(245, 158, 11, 0.55)',
  info: 'rgba(95, 169, 217, 0.45)',
};

const SEV_MAX_RADIUS: Record<string, number> = {
  critical: 6.5,
  warning: 4.5,
  info: 3.0,
};

const SEV_PERIOD_MS: Record<string, number> = {
  critical: 1400,
  warning: 1900,
  info: 2600,
};

function buildChokepointRings(): ChokepointRing[] {
  return INTEL_CHOKEPOINTS.map((cp: any): ChokepointRing => {
    const sev: string = (cp.sev as string) ?? 'info';
    const colorStr = SEV_RING_COLOR[sev] ?? SEV_RING_COLOR.info;
    return {
      lat: cp.coords[0],
      lng: cp.coords[1],
      maxR: SEV_MAX_RADIUS[sev] ?? 3,
      propagationSpeed: 1.6,
      repeatPeriod: SEV_PERIOD_MS[sev] ?? 2200,
      color: () => colorStr,
      __id: cp.id,
      __label: cp.label,
      __sev: sev,
      __desc: cp.desc,
    };
  });
}

let ringsAttached = false;

function attachChokepointRings(globe: any): void {
  if (ringsAttached) return;
  if (typeof globe.ringsData !== 'function') return;
  const rings = buildChokepointRings();
  globe
    .ringsData(rings)
    .ringLat((r: ChokepointRing) => r.lat)
    .ringLng((r: ChokepointRing) => r.lng)
    .ringMaxRadius((r: ChokepointRing) => r.maxR)
    .ringPropagationSpeed((r: ChokepointRing) => r.propagationSpeed)
    .ringRepeatPeriod((r: ChokepointRing) => r.repeatPeriod)
    .ringColor((r: ChokepointRing) => r.color);
  ringsAttached = true;
}

/** Adjust `arcDashAnimateTime` per-arc based on transit hours (if available
 * on the underlying leg payload). Falls back to whatever the legacy code
 * computed when no `hours` field is present. */
function tuneDashSpeed(globe: any, arcs: GlobeArcLike[]): void {
  // If any of the arcs carry an `hours` field, derive a dash-time inversely
  // proportional to log(hours). Otherwise, leave the legacy animTime
  // accessor in place.
  const hourly = arcs.filter((a) => typeof a.hours === 'number' && (a.hours as number) > 0);
  if (!hourly.length) return;
  const minH = Math.min(...hourly.map((a) => a.hours as number));
  const maxH = Math.max(...hourly.map((a) => a.hours as number));
  const span = Math.max(1, maxH - minH);
  globe.arcDashAnimateTime((d: GlobeArcLike) => {
    const h = typeof d.hours === 'number' && d.hours > 0 ? d.hours : minH;
    // Map [minH, maxH] -> [1200ms, 4800ms]; longer legs animate slower.
    const t = (h - minH) / span;
    return Math.round(1200 + t * 3600);
  });
}

/** Re-frame the globe to the bounding box of the chain rather than the
 * legacy centroid heuristic. Smoothly transitions over 1.8s. */
function flyToChain(globe: any, route: RouteLike): void {
  if (!route?.nodes?.length) return;
  const lats = route.nodes.map((n) => n.coords[0]);
  const lngs = route.nodes.map((n) => n.coords[1]);
  const minLat = Math.min(...lats);
  const maxLat = Math.max(...lats);
  const minLng = Math.min(...lngs);
  const maxLng = Math.max(...lngs);
  const lat = (minLat + maxLat) / 2;
  const lng = (minLng + maxLng) / 2;
  const span = Math.max(maxLat - minLat, maxLng - minLng);
  // Heuristic altitude — clamp into a usable range.
  const altitude = Math.max(0.95, Math.min(3.4, span / 50 + 0.85));
  if (typeof globe.pointOfView === 'function') {
    globe.pointOfView({ lat, lng, altitude }, 1800);
  }
}

let initialized = false;

export function initGlobeEnhancements(): void {
  if (initialized) return;
  initialized = true;

  const apply = (detail: RenderDetail): void => {
    const globe = (window as any).__heimdallGlobe;
    if (!globe) return;
    attachChokepointRings(globe);
    if (Array.isArray(detail?.arcs)) tuneDashSpeed(globe, detail.arcs);
    if (detail?.route) flyToChain(globe, detail.route);
  };

  window.addEventListener('heimdall:globe-rendered', (e: Event) => {
    const detail = (e as CustomEvent<RenderDetail>).detail;
    apply(detail);
  });

  // If the globe has already been drawn before this listener attached,
  // pick up the cached context.
  const existing = (window as any).__heimdallGlobeContext as RenderDetail | undefined;
  if (existing && (window as any).__heimdallGlobe) apply(existing);
}
