/*
 * src/main.ts — Heimdall app bootstrap.
 *
 * Phase 0: this entrypoint loads the global stylesheet bundle and the
 * legacy app module. Future view modules will be composed and wired
 * here (map init, drawer wiring, glossary engine, etc.) as the
 * monolithic src/app.ts is incrementally split.
 */
import './styles/index.css';
import './app.js';
import { initGlossaryDrawer } from './views/glossaryDrawer.js';
import { initCommandPalette } from './views/commandPalette.js';
import { initGlobeEnhancements } from './map/globeMap.js';
import { initMonteCarloUpgrade } from './services/monteCarloUpgrade.js';

function bootEnhancements(): void {
  initGlossaryDrawer();
  initCommandPalette();
  initGlobeEnhancements();
  initMonteCarloUpgrade();

  if ('serviceWorker' in navigator && window.location.protocol !== 'file:') {
    const swUrl = new URL('sw.js', window.location.href).toString();
    navigator.serviceWorker.register(swUrl, { scope: './' }).catch(() => undefined);
  }
}

if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', bootEnhancements);
} else {
  bootEnhancements();
}
