/*
 * src/glossary/glossaryEngine.ts — Glossary search & cross-link resolver.
 * Phase 1 implementation per heimdall_upgrades.md Item 1.
 */

export type GlossaryCategory =
  | 'incoterm'
  | 'trade_instrument'
  | 'regulation'
  | 'logistics'
  | 'commodity_class'
  | 'chokepoint'
  | 'market_structure';

export type GlossaryRiskClass = 'low' | 'medium' | 'high' | 'critical';

export interface GlossaryTerm {
  id: string;
  term: string;
  category: GlossaryCategory;
  shortDef: string;
  definition: string;
  applicableStages?: string[];
  riskClass: GlossaryRiskClass;
  regulatoryBody?: string | null;
  relatedTermIds?: string[];
  relatedCommodityIds?: string[];
  relatedChokepoints?: string[];
  exampleChainIds?: string[];
  incotermsRiskBoundary?: {
    sellerOwnsRiskThrough: string;
    buyerOwnsRiskFrom: string;
  };
}

export interface GlossaryCategoryDef {
  id: GlossaryCategory;
  label: string;
}

export interface GlossaryDataset {
  schemaVersion: string;
  version?: string;
  generatedAt?: string;
  categories: GlossaryCategoryDef[];
  terms: GlossaryTerm[];
}

interface ScoredTerm {
  term: GlossaryTerm;
  score: number;
}

const STOPWORDS = new Set([
  'a', 'an', 'and', 'or', 'the', 'of', 'to', 'in', 'on', 'for', 'with',
  'is', 'are', 'be', 'by', 'as', 'at', 'from', 'this', 'that', 'it',
]);

function tokenize(text: string): string[] {
  return text
    .toLowerCase()
    .replace(/[^\p{L}\p{N}\s/-]/gu, ' ')
    .split(/\s+/)
    .filter((t) => t.length >= 2 && !STOPWORDS.has(t));
}

export class GlossaryEngine {
  private readonly terms: GlossaryTerm[];
  private readonly byId: Map<string, GlossaryTerm>;
  private readonly byCategory: Map<GlossaryCategory, GlossaryTerm[]>;
  private readonly index: Map<string, Set<string>>; // token -> term ids

  constructor(dataset: GlossaryDataset) {
    this.terms = dataset.terms;
    this.byId = new Map();
    this.byCategory = new Map();
    this.index = new Map();
    for (const t of this.terms) {
      this.byId.set(t.id, t);
      const bucket = this.byCategory.get(t.category) ?? [];
      bucket.push(t);
      this.byCategory.set(t.category, bucket);
      this.indexTerm(t);
    }
  }

  private indexTerm(t: GlossaryTerm): void {
    const corpus = `${t.term} ${t.shortDef} ${t.definition}`;
    for (const tok of tokenize(corpus)) {
      const set = this.index.get(tok) ?? new Set<string>();
      set.add(t.id);
      this.index.set(tok, set);
    }
  }

  all(): GlossaryTerm[] {
    return this.terms;
  }

  getById(id: string): GlossaryTerm | undefined {
    return this.byId.get(id);
  }

  getByCategory(category: GlossaryCategory): GlossaryTerm[] {
    return this.byCategory.get(category) ?? [];
  }

  /**
   * Score per matched query token:
   *   exact term match           +6
   *   term prefix / contains     +3
   *   shortDef contains token    +2
   *   definition contains token  +1
   * Returns terms sorted by descending score, capped to `limit`.
   */
  search(query: string, limit = 20): GlossaryTerm[] {
    const q = query.trim().toLowerCase();
    if (!q) return [];
    const tokens = tokenize(q);
    if (!tokens.length) return [];
    const scores = new Map<string, number>();
    const addScore = (id: string, n: number) => {
      scores.set(id, (scores.get(id) ?? 0) + n);
    };

    for (const t of this.terms) {
      const termLower = t.term.toLowerCase();
      const shortLower = t.shortDef.toLowerCase();
      const defLower = t.definition.toLowerCase();
      if (termLower === q) addScore(t.id, 12);
      else if (termLower.startsWith(q)) addScore(t.id, 6);
      else if (termLower.includes(q)) addScore(t.id, 3);
      for (const tok of tokens) {
        if (termLower.includes(tok)) addScore(t.id, 3);
        if (shortLower.includes(tok)) addScore(t.id, 2);
        if (defLower.includes(tok)) addScore(t.id, 1);
      }
    }

    const ranked: ScoredTerm[] = [];
    for (const [id, score] of scores) {
      const term = this.byId.get(id);
      if (term && score > 0) ranked.push({ term, score });
    }
    ranked.sort((a, b) => b.score - a.score || a.term.term.localeCompare(b.term.term));
    return ranked.slice(0, limit).map((r) => r.term);
  }

  getRelated(termId: string): GlossaryTerm[] {
    const t = this.byId.get(termId);
    if (!t) return [];
    const out = new Map<string, GlossaryTerm>();
    for (const id of t.relatedTermIds ?? []) {
      const r = this.byId.get(id);
      if (r) out.set(r.id, r);
    }
    // Also pull terms that share commodities or chokepoints.
    const commoditySet = new Set(t.relatedCommodityIds ?? []);
    const chokepointSet = new Set(t.relatedChokepoints ?? []);
    if (commoditySet.size || chokepointSet.size) {
      for (const candidate of this.terms) {
        if (candidate.id === t.id || out.has(candidate.id)) continue;
        const sharesCommodity = (candidate.relatedCommodityIds ?? []).some((c) => commoditySet.has(c));
        const sharesChokepoint = (candidate.relatedChokepoints ?? []).some((c) => chokepointSet.has(c));
        if (sharesCommodity || sharesChokepoint) out.set(candidate.id, candidate);
      }
    }
    return Array.from(out.values());
  }

  /**
   * Resolve glossary terms relevant to a chain leg.
   * `commodityTags` should be lowercase commodity ids/tags from the chain.
   * `corridorIds` should be chokepoint ids that the leg's route transits.
   */
  getForLeg(opts: {
    stage?: string;
    commodityTags?: string[];
    corridorIds?: string[];
  }): GlossaryTerm[] {
    const tags = new Set((opts.commodityTags ?? []).map((s) => s.toLowerCase()));
    const corridors = new Set(opts.corridorIds ?? []);
    const out = new Map<string, GlossaryTerm>();
    for (const t of this.terms) {
      const stageMatch =
        !opts.stage ||
        !t.applicableStages?.length ||
        t.applicableStages.includes(opts.stage);
      const commodityMatch = (t.relatedCommodityIds ?? []).some((c) => tags.has(c.toLowerCase()));
      const corridorMatch = (t.relatedChokepoints ?? []).some((c) => corridors.has(c));
      if (stageMatch && (commodityMatch || corridorMatch)) {
        out.set(t.id, t);
      }
    }
    return Array.from(out.values());
  }

  getForChokepoint(chokepointId: string): GlossaryTerm[] {
    const direct = this.byId.get(chokepointId);
    const out = new Map<string, GlossaryTerm>();
    if (direct && direct.category === 'chokepoint') out.set(direct.id, direct);
    for (const t of this.terms) {
      if ((t.relatedChokepoints ?? []).includes(chokepointId)) out.set(t.id, t);
    }
    return Array.from(out.values());
  }
}

let _instance: GlossaryEngine | null = null;
let _loadPromise: Promise<GlossaryEngine> | null = null;

export async function loadGlossary(): Promise<GlossaryEngine> {
  if (_instance) return _instance;
  if (_loadPromise) return _loadPromise;
  _loadPromise = (async () => {
    const mod = await import('../../data/glossary.v1.json');
    const dataset = (mod as unknown as { default: GlossaryDataset }).default;
    _instance = new GlossaryEngine(dataset);
    return _instance;
  })();
  return _loadPromise;
}

export function getLoadedGlossary(): GlossaryEngine | null {
  return _instance;
}
